#include <stdio.h>
#include <stdlib.h>

// Define the structure for a tree node
typedef struct TreeNode {
    int val;
    struct TreeNode* left;
    struct TreeNode* right;
} TreeNode;

// Function to create a new tree node
TreeNode* createTreeNode(int val) {
    TreeNode* newNode = (TreeNode*) malloc(sizeof(TreeNode));
    if (!newNode) {
        printf("Memory error
");
        return NULL;
    }
    newNode->val = val;
    newNode->left = newNode->right = NULL;
    return newNode;
}

// Function to perform postorder traversal
void postorderTraversal(TreeNode* root, int** result, int* returnSize) {
    if (root) {
        postorderTraversal(root->left, result, returnSize);
        postorderTraversal(root->right, result, returnSize);
        (*result)[(*returnSize)++] = root->val;
    }
}

// Function to get the postorder traversal of a binary tree
int* postorderTraversalOfTree(TreeNode* root, int* returnSize) {
    *returnSize = 0;
    int* result = (int*) malloc(100 * sizeof(int));
    postorderTraversal(root, &result, returnSize);
    return result;
}

